        method: 'GET',
        url: url,
        headers: headers,
      );

      final response = await http.get(
        Uri.parse(url),
        headers: headers,
      );

      final duration = DateTime.now().difference(startTime);
      ProductionLogger.logHttpCall(
        method: 'GET',
        url: url,
        statusCode: response.statusCode,
        duration: duration,
